local c=component local g,s local w,h=80,25 local function i()local gi=c.list('gpu')if gi then if type(gi)=='function'then local a=gi()while type(a)~='string'and gi do a=gi()end if a then g=c.proxy(a)end elseif type(gi)=='table'then for _,a in pairs(gi)do if type(a)=='string'then g=c.proxy(a)break end end end end local si=c.list('screen')if si then if type(si)=='function'then local a=si()while type(a)~='string'and si do a=si()end if a then s=a end elseif type(si)=='table'then for _,a in pairs(si)do if type(a)=='string'then s=a break end end end end if g and s then g.bind(s)w,h=g.getResolution()else error'No GPU'end end i()local p='/System/OS/bios.cfg'local cfg={bd=3,bi={},df=nil}local fs local f=c.list('filesystem')if f then if type(f)=='function'then local a=f()while type(a)~='string'and f do a=f()end if a then fs=c.proxy(a)end elseif type(f)=='table'then for _,a in pairs(f)do if type(a)=='string'then fs=c.proxy(a)break end end end end local function l()if fs and fs.exists(p)then local f=fs.open(p,'r')if f then local d=fs.read(f)fs.close(f)local fn=load('return '..d)if fn then cfg=fn()end end end end local function s()local s='{'for k,v in pairs(cfg)do if type(v)~='function'then s=s..('%q'):format(k)..'='if type(v)=='table'then s=s..'{},'else s=s..('%q'):format(v)..','end end end s=s..'}'if fs then local f=fs.open(p,'w')if f then fs.write(f,s)fs.close(f)end end end local function cls(c)g.fill(1,1,w,h,c or 0x2D2D2D,' ')end local function txt(x,y,s,c)g.setForeground(c or 0xFFFFFF)g.set(x,y,s)end local function scan()local t={}local f=c.list('filesystem')if f then if type(f)=='function'then for a in f do local p=c.proxy(a)if p and(p.exists('/OS.lua')or p.exists('/init.lua'))then table.insert(t,{name=p.getLabel()or'Disk',path=a})end end elseif type(f)=='table'then for _,a in pairs(f)do if type(a)=='string'then local p=c.proxy(a)if p and(p.exists('/OS.lua')or p.exists('/init.lua'))then table.insert(t,{name=p.getLabel()or'Disk',path=a})end end end end end return t end local function getE()local ei=c.list('eeprom')if ei then if type(ei)=='function'then local a=ei()while type(a)~='string'and ei do a=ei()end return a elseif type(ei)=='table'then for _,a in pairs(ei)do if type(a)=='string'then return a end end end end end local function main()l()local f12=false t=c.uptime()while c.uptime()-t<cfg.bd do local e={c.pullSignal(0.1)}if e[1]=='key_down'and e[4]==88 then f12=true break end end if not f12 then cls()txt(2,2,'Booting...')local def=cfg.df and cfg.bi[cfg.df]local e=getE()if e then if def then c.invoke(e,'setData',def.path)elseif #cfg.bi>0 then c.invoke(e,'setData',cfg.bi[1].path)else c.invoke(e,'setData','')end end c.shutdown(true)return end end if #cfg.bi==0 then local d=scan()for i,v in ipairs(d)do table.insert(cfg.bi,{name=v.name,path=v.path})end s()end cls()txt(2,2,'Boot Menu')for i,item in ipairs(cfg.bi)do txt(2,4+i,item.name)end local sel=1 while true do cls()txt(2,2,'Boot Menu')for i,item in ipairs(cfg.bi)do txt(2,4+i,(i==sel and'> 'or'  ')..item.name)end local e={c.pullSignal()}if e[1]=='key_down'then if e[4]==200 and sel>1 then sel=sel-1 elseif e[4]==208 and sel<#cfg.bi then sel=sel+1 elseif e[4]==28 then local e=getE()if e then c.invoke(e,'setData',cfg.bi[sel].path)end c.shutdown(true)elseif e[4]==19 then c.shutdown(true)end end end end local ok,err=pcall(main)if not ok then cls()txt(2,2,err,0xFF0000)txt(2,4,'Press any key')c.pullSignal()end